// Role represents a user role with specific permissions
type Role string

const (
	RolePlayer    Role = "player"
	RoleModerator Role = "moderator"
	RoleAdmin     Role = "admin"
)

// Permission represents a specific action permission
type Permission string

const (
	PermKick      Permission = "kick"
	PermBan       Permission = "ban"
	PermGiveItems Permission = "giveitems"
	PermChat      Permission = "chat"
)

// RolePermissions defines the server-authoritative mapping of roles to permissions.
// Client-provided role information is NEVER trusted.
var RolePermissions = map[Role][]Permission{
	RolePlayer:    {PermChat},
	RoleModerator: {PermChat, PermKick},
	RoleAdmin:     {PermChat, PermKick, PermBan, PermGiveItems},
}

