func NewUserStore() *UserStore {
	return &UserStore{
		users:  make(map[string]*User),
		byName: make(map[string]string),
	}
}

func (us *UserStore) GetByID(id string) (*User, bool) {
	us.mu.RLock()
	defer us.mu.RUnlock()
	u, ok := us.users[id]
	if !ok {
		return nil, false
	}
	// Return a copy to prevent race conditions
	copy := *u
	return &copy, true
}

func (us *UserStore) GetByUsername(username string) (*User, bool) {
	us.mu.RLock()
	defer us.mu.RUnlock()
	id, ok := us.byName[strings.ToLower(username)]
	if !ok {
		return nil, false
	}
	u, ok := us.users[id]
	if !ok {
		return nil, false
	}
	copy := *u
	return &copy, true
}

func (us *UserStore) CreateUser(username, password string, role Role) (*User, error) {
	us.mu.Lock()
	defer us.mu.Unlock()

	normalizedName := strings.ToLower(username)
	if _, exists := us.byName[normalizedName]; exists {
		return nil, fmt.Errorf("username already exists")
	}

	// Validate role is a known role
	if !isValidRole(role) {
		return nil, fmt.Errorf("invalid role")
	}

	// Validate username (alphanumeric, 3-20 chars)
	if !isValidUsername(username) {
		return nil, fmt.Errorf("invalid username: must be 3-20 alphanumeric characters")
	}

	// Validate password strength
	if len(password) < 12 {
		return nil, fmt.Errorf("password must be at least 12 characters")
	}

	hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
	if err != nil {
		return nil, fmt.Errorf("failed to hash password: %w", err)
	}

	id, err := generateSecureID()
	if err != nil {
		return nil, fmt.Errorf("failed to generate user ID: %w", err)
	}

	user := &User{
		ID:           id,
		Username:     username,
		PasswordHash: string(hash),
		Role:         role,
	}

	us.users[id] = user
	us.byName[normalizedName] = id
	return user, nil
}

func (us *UserStore) UpdateUser(user *User) {
	us.mu.Lock()
	defer us.mu.Unlock()
	us.users[user.ID] = user
}

func (us *UserStore) IncrementFailedAttempts(userID string) {
	us.mu.Lock()
	defer us.mu.Unlock()
	if u, ok := us.users[userID]; ok {
		u.FailedAttempts++
		if u.FailedAttempts >= 5 {
			u.LockedUntil = time.Now().Add(15 * time.Minute)
			u.FailedAttempts = 0
		}
	}
}

func (us *UserStore) ResetFailedAttempts(userID string) {
	us.mu.Lock()
	defer us.mu.Unlock()
	if u, ok := us.users[userID]; ok {
		u.FailedAttempts = 0
		u.LockedUntil = time.Time{}
	}
}

func NewSessionStore() *SessionStore {
	return &SessionStore{
		sessions: make(map[string]*Session),
	}
}

func (ss *SessionStore) CreateSession(userID string) (string, error) {
	token, err := generateSecureToken()
	if err != nil {
		return "", err
	}

	// Store a hash of the token, not the token itself
	tokenHash := hashToken(token)

	ss.mu.Lock()
	defer ss.mu.Unlock()

	session := &Session{
		Token:     tokenHash,
		UserID:    userID,
		CreatedAt: time.Now(),
		ExpiresAt: time.Now().Add(1 * time.Hour),
	}
	ss.sessions[tokenHash] = session

	return token, nil
}

func (ss *SessionStore) ValidateSession(token string) (*Session, bool) {
	tokenHash := hashToken(token)

	ss.mu.RLock()
	defer ss.mu.RUnlock()

	session, ok := ss.sessions[tokenHash]
	if !ok {
		return nil, false
	}

	if time.Now().After(session.ExpiresAt) {
		// Session expired - clean up in a separate goroutine to avoid holding the lock
		go ss.DeleteSession(token)
		return nil, false
	}

	return session, true
}

func (ss *SessionStore) DeleteSession(token string) {
	tokenHash := hashToken(token)
	ss.mu.Lock()
	defer ss.mu.Unlock()
	delete(ss.sessions, tokenHash)
}

