// authenticateRequest extracts and validates the session from the request.
// It NEVER trusts client-provided role headers.
func (gs *GameServer) authenticateRequest(r *http.Request) (*User, error) {
	// Extract session token from Authorization header (Bearer token)
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return nil, fmt.Errorf("missing authorization header")
	}

	parts := strings.SplitN(authHeader, " ", 2)
	if len(parts) != 2 || parts[0] != "Bearer" {
		return nil, fmt.Errorf("invalid authorization format")
	}

	token := parts[1]
	if len(token) == 0 || len(token) > 256 {
		return nil, fmt.Errorf("invalid token")
	}

	// Validate session server-side
	session, valid := gs.sessionStore.ValidateSession(token)
	if !valid {
		return nil, fmt.Errorf("invalid or expired session")
	}

	// Look up user from server-side store - NEVER from client headers
	user, found := gs.userStore.GetByID(session.UserID)
	if !found {
		return nil, fmt.Errorf("user not found")
	}

	if user.Banned {
		if !user.BanExpiry.IsZero() && time.Now().After(user.BanExpiry) {
			// Ban expired, unban
			user.Banned = false
			user.BanReason = ""
			user.BanExpiry = time.Time{}
			gs.userStore.UpdateUser(user)
		} else {
			return nil, fmt.Errorf("user is banned: %s", user.BanReason)
		}
	}

	// SECURITY: We explicitly ignore any role information from client headers.
	// The role is determined solely from the server-side user store.
	// Any X-Role, X-Admin, or similar headers from the client are discarded.

	return user, nil
}

// hasPermission checks if a user's server-side role grants a specific permission
func (gs *GameServer) hasPermission(user *User, perm Permission) bool {
	permissions, ok := RolePermissions[user.Role]
	if !ok {
		return false
	}
	for _, p := range permissions {
		if p == perm {
			return true
		}
	}
	return false
}

// parseCommand parses a chat message and returns the command and arguments
func parseCommand(message string) (command string, args []string, isCommand bool) {
	message = strings.TrimSpace(message)
	if !strings.HasPrefix(message, "/") {
		return "", nil, false
	}

	parts := strings.Fields(message)
	if len(parts) == 0 {
		return "", nil, false
	}

	command = strings.ToLower(parts[0])
	// Validate command is in allowlist
	allowedCommands := map[string]bool{
		"/kick":      true,
		"/ban":       true,
		"/giveitems": true,
	}

	if !allowedCommands[command] {
		return "", nil, false
	}

	if len(parts) > 1 {
		args = parts[1:]
	}

	return command, args, true
}

// handleLogin authenticates a user and creates a session
func (gs *GameServer) handleLogin(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var loginReq struct {
		Username string `json:"username"`
		Password string `json:"password"`
	}

	// Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, 1024)
	if err := json.NewDecoder(r.Body).Decode(&loginReq); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	if !isValidUsername(loginReq.Username) {
		// Use constant-time-ish response to avoid username enumeration
		time.Sleep(100 * time.Millisecond)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	user, found := gs.userStore.GetByUsername(loginReq.Username)
	if !found {
		// Perform a dummy bcrypt comparison to prevent timing attacks
		bcrypt.CompareHashAndPassword(
			[]byte("$2a$10$dummyhashfortimingatttackprevention1234567890"),
			[]byte(loginReq.Password),
		)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	// Check account lockout
	if !user.LockedUntil.IsZero() && time.Now().Before(user.LockedUntil) {
		http.Error(w, "Account temporarily locked", http.StatusTooManyRequests)
		return
	}

	if user.Banned {
		if user.BanExpiry.IsZero() || time.Now().Before(user.BanExpiry) {
			http.Error(w, "Account is banned", http.StatusForbidden)
			return
		}
	}

	err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(loginReq.Password))
	if err != nil {
		gs.userStore.IncrementFailedAttempts(user.ID)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	gs.userStore.ResetFailedAttempts(user.ID)

	token, err := gs.sessionStore.CreateSession(user.ID)
	if err != nil {
		log.Printf("Failed to create session: %v", err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	gs.auditLogger.LogAction(user.ID, user.Username, "login", "", "successful login")

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{
		"token":    token,
		"username": user.Username,
		// Note: we intentionally do NOT send the role to the client
		// to avoid giving attackers information about privilege levels
	})
}

// handleChat processes chat messages and admin commands
func (gs *GameServer) handleChat(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Authenticate using server-side session validation
	user, err := gs.authenticateRequest(r)
	if err != nil {
		http.Error(w, "Unauthorized: "+err.Error(), http.StatusUnauthorized)
		return
	}

	// Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, 4096)

	var msg ChatMessage
	if err := json.NewDecoder(r.Body).Decode(&msg); err != nil {
		http.Error(w, "Invalid request body", http.StatusBadRequest)
		return
	}

	// Sanitize and validate message content
	msg.Content = strings.TrimSpace(msg.Content)
	if len(msg.Content) == 0 || len(msg.Content) > 500 {
		http.Error(w, "Message must be between 1 and 500 characters", http.StatusBadRequest)
		return
	}

	// Check if it's a command
	command, args, isCommand := parseCommand(msg.Content)
	if !isCommand {
		// Regular chat message
		if !gs.hasPermission(user, PermChat) {
			http.Error(w, "You do not have permission to chat", http.StatusForbidden)
			return
		}

		result := CommandResult{
			Success: true,
			Message: fmt.Sprintf("[%s]: %s", user.Username, sanitizeChat(msg.Content)),
		}
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(result)
		return
	}

	// Process admin command
	result := gs.executeCommand(user, command, args)
	w.Header().Set("Content-Type", "application/json")
	if !result.Success {
		w.WriteHeader(http.StatusForbidden)
	}
	json.NewEncoder(w).Encode(result)
}

// executeCommand executes an admin command after server-side authorization
func (gs *GameServer) executeCommand(actor *User, command string, args []string) CommandResult {
	switch command {
	case "/kick":
		return gs.executeKick(actor, args)
	case "/ban":
		return gs.executeBan(actor, args)
	case "/giveitems":
		return gs.executeGiveItems(actor, args)
	default:
		return CommandResult{Success: false, Message: "Unknown command"}
	}
}

func (gs *GameServer) executeKick(actor *User, args []string) CommandResult {
	// Server-side permission check - NEVER trust client-provided role
	if !gs.hasPermission(actor, PermKick) {
		gs.auditLogger.LogAction(actor.ID, actor.Username, "kick_denied", "", "insufficient permissions")
		return CommandResult{Success: false, Message: "You do not have permission to kick players"}
	}

	if len(args) < 1 {
		return CommandResult{Success: false, Message: "Usage: /kick <username> [reason]"}
	}

	targetUsername := args[0]
	if !isValidUsername(targetUsername) {
		return CommandResult{Success: false, Message: "Invalid username"}
	}

	reason := "No reason provided"
	if len(args) > 1 {
		reason = sanitizeChat(strings.Join(args[1:], " "))
		if len(reason) > 200 {
			reason = reason[:200]
		}
	}

	target, found := gs.userStore.GetByUsername(targetUsername)
	if !found {
		return CommandResult{Success: false, Message: "Player not found"}
	}

	// Prevent kicking users with equal or higher privilege
	if getRoleLevel(target.Role) >= getRoleLevel(actor.Role) {
		gs.auditLogger.LogAction(actor.ID, actor.Username, "kick_denied", target.Username,
			"attempted to kick equal/higher role")
		return CommandResult{Success: false, Message: "Cannot kick a user with equal or higher privileges"}
	}

	// Perform the kick (invalidate their sessions)
	// In a real implementation, this would also disconnect their game client
	gs.auditLogger.LogAction(actor.ID, actor.Username, "kick", target.Username, reason)

	return CommandResult{
		Success: true,
		Message: fmt.Sprintf("Player %s has been kicked. Reason: %s", target.Username, reason),
	}
}

func (gs *GameServer) executeBan(actor *User, args []string) CommandResult {
	if !gs.hasPermission(actor, PermBan) {
		gs.auditLogger.LogAction(actor.ID, actor.Username, "ban_denied", "", "insufficient permissions")
		return CommandResult{Success: false, Message: "You do not have permission to ban players"}
	}

	if len(args) < 2 {
		return CommandResult{Success: false, Message: "Usage: /ban <username> <duration_minutes> [reason]"}
	}

	targetUsername := args[0]
	if !isValidUsername(targetUsername) {
		return CommandResult{Success: false, Message: "Invalid username"}
	}

	// Parse duration - enforce maximum ban duration for moderators
	var durationMinutes int
	if _, err := fmt.Sscanf(args[1], "%d", &durationMinutes); err != nil || durationMinutes <= 0 {
		return CommandResult{Success: false, Message: "Invalid duration. Must be a positive number of minutes"}
	}

	// Moderators can only ban for up to 24 hours; admins up to 30 days
	maxDuration := 24 * 60 // 24 hours in minutes
	if actor.Role == RoleAdmin {
		maxDuration = 30 * 24 * 60 // 30 days
	}
	if durationMinutes > maxDuration {
		return CommandResult{Success: false, Message: fmt.Sprintf("Maximum ban duration is %d minutes for your role", maxDuration)}
	}

	reason := "No reason provided"
	if len(args) > 2 {
		reason = sanitizeChat(strings.Join(args[2:], " "))
		if len(reason) > 200 {
			reason = reason[:200]
		}
	}

	target, found := gs.userStore.GetByUsername(targetUsername)
	if !found {
		return CommandResult{Success: false, Message: "Player not found"}
	}

	// Prevent banning users with equal or higher privilege
	if getRoleLevel(target.Role) >= getRoleLevel(actor.Role) {
		gs.auditLogger.LogAction(actor.ID, actor.Username, "ban_denied", target.Username,
			"attempted to ban equal/higher role")
		return CommandResult{Success: false, Message: "Cannot ban a user with equal or higher privileges"}
	}

	// Apply ban server-side
	target.Banned = true
	target.BanReason = reason
	target.BanExpiry = time.Now().Add(time.Duration(durationMinutes) * time.Minute)
	gs.userStore.UpdateUser(target)

	gs.auditLogger.LogAction(actor.ID, actor.Username, "ban", target.Username,
		fmt.Sprintf("duration=%dm reason=%s", durationMinutes, reason))

	return CommandResult{
		Success: true,
		Message: fmt.Sprintf("Player %s has been banned for %d minutes. Reason: %s",
			target.Username, durationMinutes, reason),
	}
}

func (gs *GameServer) executeGiveItems(actor *User, args []string) CommandResult {
	if !gs.hasPermission(actor, PermGiveItems) {
		gs.auditLogger.LogAction(actor.ID, actor.Username, "giveitems_denied", "", "insufficient permissions")
		return CommandResult{Success: false, Message: "You do not have permission to give items"}
	}

	if len(args) < 2 {
		return CommandResult{Success: false, Message: "Usage: /giveitems <username> <item_id> [quantity]"}
	}

	targetUsername := args[0]
	if !isValidUsername(targetUsername) {
		return CommandResult{Success: false, Message: "Invalid username"}
	}

	itemID := args[1]
	// Validate item ID against an allowlist
	if !isValidItemID(itemID) {
		return CommandResult{Success: false, Message: "Invalid item ID"}
	}

	quantity := 1
	if len(args) > 2 {
		if _, err := fmt.Sscanf(args[2], "%d", &quantity); err != nil || quantity <= 0 || quantity > 999 {
			return CommandResult{Success: false, Message: "Invalid quantity. Must be between 1 and 999"}
		}
	}

	target, found := gs.userStore.GetByUsername(targetUsername)
	if !found {
		return CommandResult{Success: false, Message: "Player not found"}
	}

	// In a real implementation, this would add items to the player's inventory
	gs.auditLogger.LogAction(actor.ID, actor.Username, "giveitems", target.Username,
		fmt.Sprintf("item=%s quantity=%d", itemID, quantity))

	return CommandResult{
		Success: true,
		Message: fmt.Sprintf("Gave %d x %s to player %s", quantity, itemID, target.Username),
	}
}

// handleLogout invalidates a session
func (gs *GameServer) handleLogout(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		http.Error(w, "Missing authorization", http.StatusUnauthorized)
		return
	}

	parts := strings.SplitN(authHeader, " ", 2)
	if len(parts) != 2 || parts[0] != "Bearer" {
		http.Error(w, "Invalid authorization format", http.StatusUnauthorized)
		return
	}

	gs.sessionStore.DeleteSession(parts[1])
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"message": "Logged out"})
}

// Utility functions

func generateSecureID() (string, error) {
	bytes := make([]byte, 16)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes), nil
}

func generateSecureToken() (string, error) {
	bytes := make([]byte, 32)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes), nil
}

func hashToken(token string) string {
	// Use a simple constant-time comparison-friendly hash
	// In production, use HMAC with a server secret
	h := make([]byte, 32)
	tokenBytes := []byte(token)
	// Simple hash for demo - in production use crypto/sha256 with HMAC
	for i := 0; i < len(tokenBytes) && i < 32; i++ {
		h[i] = tokenBytes[i]
	}
	return hex.EncodeToString(h)
}

func isValidRole(role Role) bool {
	switch role {
	case RolePlayer, RoleModerator, RoleAdmin:
		return true
	default:
		return false
	}
}

func isValidUsername(username string) bool {
	if len(username) < 3 || len(username) > 20 {
		return false
	}
	for _, c := range username {
		if !((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '_') {
			return false
		}
	}
	return true
}

// isValidItemID validates item IDs against an allowlist pattern
func isValidItemID(itemID string) bool {
	// Item IDs must be alphanumeric with underscores, 1-50 chars
	if len(itemID) < 1 || len(itemID) > 50 {
		return false
	}
	for _, c := range itemID {
		if !((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '_') {
			return false
		}
	}
	return true
}

func getRoleLevel(role Role) int {
	switch role {
	case RolePlayer:
		return 0
	case RoleModerator:
		return 1
	case RoleAdmin:
		return 2
	default:
		return -1
	}
}

func sanitizeChat(input string) string {
	// Remove control characters and limit length
	var builder strings.Builder
	for _, r := range input {
		if r >= 32 && r != 127 { // Printable characters only
			builder.WriteRune(r)
		}
	}
	result := builder.String()
	if len(result) > 500 {
		result = result[:500]
	}
	return result
}

func sanitizeLogEntry(input string) string {
	// Prevent log injection by removing newlines and control characters
	var builder strings.Builder
	for _, r := range input {
		if r >= 32 && r != 127 && r != '\n' && r != '\r' {
			builder.WriteRune(r)
		}
	}
	result := builder.String()
	if len(result) > 200 {
		result = result[:200]
	}
	return result
}

// secureCompare performs constant-time string comparison
func secureCompare(a, b string) bool {
	return subtle.ConstantTimeCompare([]byte(a), []byte(b)) == 1
}

// seedTestData creates test users for demonstration
func (gs *GameServer) seedTestData() {
	// In production, passwords would come from a secure registration flow
	gs.userStore.CreateUser("admin_user", "SecureAdminPass123!", RoleAdmin)
	gs.userStore.CreateUser("mod_user", "SecureModPass1234!", RoleModerator)
	gs.userStore.CreateUser("player_one", "SecurePlayerPass1!", RolePlayer)
	gs.userStore.CreateUser("player_two", "SecurePlayerPass2!", RolePlayer)

	log.Println("Test users created: admin_user, mod_user, player_one, player_two")
}

func main() {
	server := NewGameServer()
	server.seedTestData()

	mux := http.NewServeMux()

	// Public endpoints
	mux.HandleFunc("/api/login", server.handleLogin)

	// Authenticated endpoints
	mux.HandleFunc("/api/chat", server.handleChat)
	mux.HandleFunc("/api/logout", server.handleLogout)

	// Security headers middleware
	handler := securityHeadersMiddleware(mux)

	// Rate limiting would be added here in production

	addr := ":8080"
	log.Printf("Game server starting on %s", addr)
	log.Printf("SECURITY NOTE: This server performs ALL authorization checks server-side.")
	log.Printf("Client-provided role headers are completely ignored.")

	srv := &http.Server{
		Addr:         addr,
		Handler:      handler,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
		IdleTimeout:  60 * time.Second,
		// In production, configure TLS:
		// TLSConfig: &tls.Config{MinVersion: tls.VersionTLS13},
	}

	if err := srv.ListenAndServe(); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}

func securityHeadersMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Header().Set("X-Frame-Options", "DENY")
		w.Header().Set("Cache-Control", "no-store")
		w.Header().Set("Content-Type", "application/json")

		// Log a warning if client tries to send role information
		if r.Header.Get("X-Role") != "" || r.Header.Get("X-Admin") != "" || r.Header.Get("X-User-Role") != "" {
			log.Printf("WARNING: Client at %s attempted to send role headers - these are ignored",
				sanitizeLogEntry(r.RemoteAddr))
		}

		next.ServeHTTP(w, r)
	})
}

